import { replaceOrThrow } from './prompt-utils.js';

export class WriterPromptBuilder {
  constructor(options = {}) {
    this.options = {
      tone: 'neutral',
      format: 'plain-text',
      length: 'short',
      outputLanguage: 'en',
      sharedContext: '',
      context: '',
      ...options,
    };
  }

  getLanguageName(code) {
    if (!code) {
      return 'English';
    }
    try {
      const regionNames = new Intl.DisplayNames(['en'], { type: 'language' });
      return regionNames.of(code) || 'English';
    } catch (e) {
      return 'English';
    }
  }

  /**
   * Generates a parametrized prompt object.
   */
  buildPrompt(inputText, runtimeOptions = {}) {
    const mergedOptions = { ...this.options, ...runtimeOptions };
    const { tone, format, length, outputLanguage, sharedContext, context } =
      mergedOptions;

    // 1. Get System Prompt Template
    const key = `${tone}|${format}|${length}`;
    let systemPrompt =
      PROMPT_LOOKUP[key] || PROMPT_LOOKUP['neutral|plain-text|short'];


    // 2. Parametrize Language
    systemPrompt = replaceOrThrow(
      systemPrompt,
      /You MUST write exclusively and entirely in (Japanese|English)\./,
      `You MUST write exclusively and entirely in ${this.getLanguageName(outputLanguage)}.`,
      'language'
    );

    // 3. Parametrize Context Instructions
    const hasContext = !!sharedContext || !!context;
    const contextInstruction =
      '### CONTEXT GUIDANCE\nUse the provided context to inform the tone and style, but do not output the context itself.';

    if (!hasContext) {
      systemPrompt = replaceOrThrow(
        systemPrompt,
        contextInstruction,
        '',
        'context instruction'
      );
    }

    // 4. Construct User Prompt
    let userPrompt = '';
    if (!hasContext) {
      userPrompt = `TEXT: ${inputText}`;
    } else {
      // sharedContext always appears before context
      const combinedContext = `${sharedContext || ''} ${context || ''}`.trim();
      userPrompt = `CONTEXT: ${combinedContext} TEXT: ${inputText}`;
    }

    // 5. Return structured object
    const prompt = {
      systemPrompt,
      userPrompt,
    };
    console.debug('WriterPromptBuilder prompt:', prompt);
    return prompt;
  }
}
